.drop-zone {
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 160px;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    background-color: #f8f9fa;
    color: #6c757d;
    font-size: 1.1rem;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

::deep .drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
    color: #0d6efd;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    margin-bottom: 0.5rem;
    background: #fff;
}

.file-entry.file-error {
    border-color: #dc3545;
    background: #fff5f5;
}

.file-info {
    flex: 1;
}

.error-message {
    color: #dc3545;
    font-weight: 600;
    font-size: 0.9rem;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.25rem 0.6rem;
    cursor: pointer;
    font-size: 0.85rem;
    transition: background-color 0.15s, color 0.15s;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

